        import org.apache.log4j.Logger;
        import sailpoint.object.Identity;
        import sailpoint.server.Auditor;
        import sailpoint.object.AuditEvent;    
        String prevType=null;
        String newType=null;
        String strEmail = null;
        String gStatus = null;
        String prevgStatus = null;
        try{

        if(event != null){

        Identity oldIdentity = event.getOldObject();
        Identity newIdentity = event.getNewObject();
        if(oldIdentity!=null && newIdentity!=null){
        prevType = oldIdentity.getType();
        newType = newIdentity.getType();
        prevgStatus = oldIdentity.getStringAttribute("gsuiteStatus");
        }
        } else if(null != inputMap){
        newType = inputMap.get("new_type");  
        prevType = inputMap.get("old_type");
        prevgStatus = inputMap.get("old_gsuite_status");
        }
        Identity identity = context.getObjectByName(Identity.class, identityName);

        if(null!=identity){
        modifyGsuiteLicense(identityName,"typeChange"); 
        if(null!=identity.getAttribute("email"))
        {
        strEmail=identity.getAttribute("email");
        }
        if(null!=identity.getAttribute("gsuiteStatus"))
        {
        gStatus=identity.getAttribute("gsuiteStatus");
        }

        identity.setAttribute("ctrexpDt", " ");
        context.saveObject(identity);

        //Write Audit records to IIQ.
        String auditString1 = "Identity that was processed-Type Change: "+identityName;
        String auditString2 = "Previous Type Value : "+prevType +", New EmpType value : "+newType;
        String auditString3 = "Previous GSuite Status : "+prevgStatus +", New Gsuite Status : "+gStatus;

        String strAction=null;
        String strTarget=null;
        AuditEvent adtEvent=null;

        strTarget=identityName;
        strAction = "UserTypeChange";
        if(Auditor.isEnabled(strAction)){
        adtEvent = new AuditEvent();
        adtEvent.setSource("UserTypeChange");
        adtEvent.setTarget(strTarget);
        adtEvent.setAction(strAction);
        adtEvent.setAccountName(strEmail);
        adtEvent.setAttributeName("UserTypeChange Process");
        adtEvent.setApplication("IIQ");

        adtEvent.setString1(auditString1);
        adtEvent.setString2(auditString2);
        adtEvent.setString3(auditString3);

        Auditor.log(adtEvent);
        context.commitTransaction();

        }
        }
        }catch(Exception e){

        throw e;
        }
